import stylesText from './deck-card.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';

const styles = cssStyleSheet(stylesText);
import type { DeckStat } from '@motivation/shared';

const template = document.createElement('template');
template.innerHTML = `
    <div class="deck-card">
        <div class="deck-info">
            <h3 class="deck-name" id="deck-name"></h3>
            <p class="deck-description" id="deck-description" hidden></p>
        </div>
        <div class="deck-meta">
            <span class="deck-total" id="deck-total"></span>
            <span class="deck-status" id="deck-status"></span>
        </div>
    </div>
`;

export class DeckCard extends HTMLElement {
    private _deck?: DeckStat;

    private deckCardEl: HTMLElement;
    private nameEl: HTMLElement;
    private descriptionEl: HTMLElement;
    private totalEl: HTMLElement;
    private statusEl: HTMLElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        this.deckCardEl = shadow.querySelector('.deck-card') as HTMLElement;
        this.nameEl = shadow.getElementById('deck-name') as HTMLElement;
        this.descriptionEl = shadow.getElementById('deck-description') as HTMLElement;
        this.totalEl = shadow.getElementById('deck-total') as HTMLElement;
        this.statusEl = shadow.getElementById('deck-status') as HTMLElement;
    }

    connectedCallback() {
        if (this._deck) this.render();
    }

    set deck(stat: DeckStat | undefined) {
        this._deck = stat;
        if (this.isConnected) {
            this.render();
        }
    }

    get deck(): DeckStat | undefined {
        return this._deck;
    }

    private render() {
        if (!this._deck) return;
        const stat = this._deck;

        // Status classification
        let statusClass: string;
        let statusLabel: string;
        let hostState: string;

        if (stat.due_cards > 0) {
            statusClass = 'has-due';
            statusLabel = `${stat.due_cards} due`;
            hostState = 'state-due';
        } else if (stat.new_cards > 0) {
            statusClass = 'has-new';
            statusLabel = `${stat.new_cards} new`;
            hostState = 'state-new';
        } else {
            statusClass = 'up-to-date';
            statusLabel = 'all caught up';
            hostState = '';
        }

        this.dataset.state = hostState;
        this.deckCardEl.className = `deck-card ${hostState}`.trim();
        this.nameEl.textContent = stat.name;
        this.totalEl.textContent = `${stat.total_cards} card${stat.total_cards !== 1 ? 's' : ''}`;

        if (stat.description) {
            this.descriptionEl.hidden = false;
            this.descriptionEl.textContent = stat.description;
        } else {
            this.descriptionEl.hidden = true;
            this.descriptionEl.textContent = '';
        }

        this.statusEl.className = `deck-status ${statusClass}`;
        this.statusEl.textContent = statusLabel;
    }
}

customElements.define('deck-card', DeckCard);
